class Student
{
public:
    string name;

    void setName(string name) // parameter also called 'name'!
    {
        name = name; // does nothing useful — just assigns the parameter to itself
    }
};

void setName(string name)
{
    this->name = name; // this->name is the MEMBER; name (alone) is the parameter
}

#include <iostream>
#include <string>

using namespace std;

class Student
{
public:
    string name;

    void setName(string name)
    {
        this->name = name;
    }

    void display()
    {
        cout << this->name;
    }
};

int main()
{
    Student s1;
    s1.setName("Aman");

    s1.display();

    return 0;
}

Student& setName(string name)
{
    this->name = name;
    return *this; // returns the object itself, enabling chaining
}

// later: s1.setName("Aman").setAge(20).display();

